  <script>
    function enforceTimeDifference(startSelector, endSelector, minMinutes, maxMinutes) {
      var isAdjusting = false;
      var startInput = document.querySelector(startSelector);
      var endInput = document.querySelector(endSelector);

      if (!startInput || !endInput) {
        return;
      }

      startInput.addEventListener('change', function() {
        if (isAdjusting) return;
        isAdjusting = true;

        var startTime = startInput.value;
        var endTime = endInput.value;

        if (startTime && endTime) {
          var start = parseTime(startTime);
          var end = parseTime(endTime);
          var diff = end - start;

          if (diff < minMinutes) {
            endInput.value = formatTime(start + minMinutes);
          } else if (diff > maxMinutes) {
            endInput.value = formatTime(start + maxMinutes);
          }
        }

        isAdjusting = false;
      });

      endInput.addEventListener('change', function() {
        if (isAdjusting) return;

        var endTime = endInput.value;
        var startTime = startInput.value;

        if (!startTime || !endTime) {
          return;
        }

        var start = parseTime(startTime);
        var end = parseTime(endTime);
        var diff = end - start;

        if (diff < minMinutes || diff > maxMinutes) {
          endInput.setCustomValidity('La hora de fin debe estar entre ' + minMinutes + ' y ' + maxMinutes + ' minutos despues de la hora de inicio.');
        } else {
          endInput.setCustomValidity('');
        }
      });
    }

    document.addEventListener('DOMContentLoaded', function() {
      var editarVisitaModalElement = document.getElementById('editarVisitaModal');
      var editarVisitaModal = editarVisitaModalElement ? new bootstrap.Modal(editarVisitaModalElement) : null;
      var editarVisitaForm = document.getElementById('editarVisitaForm');
      var editarVisitaFeedback = document.getElementById('editarVisitaFeedback');
      var editarVisitaId = document.getElementById('editarVisitaId');
      var editarVisitaResumen = document.getElementById('editarVisitaResumen');
      var visitaPedidoCalendarEl = document.getElementById('visitaPedidoCalendar');
      var visitaPedidoCalendar = null;
      var visitaEditor = null;

      if (visitaPedidoCalendarEl && window.initSharedFullCalendar) {
        visitaPedidoCalendar = window.initSharedFullCalendar({
          element: visitaPedidoCalendarEl,
          initialView: 'timeGridDay',
          height: '100%',
          onEventClick: function(info) {
            if (visitaEditor) {
              visitaEditor.open(info.event.id);
            }
          }
        });
      }

      if (window.initVisitaEditorModal) {
        visitaEditor = window.initVisitaEditorModal({
          getCalendar: function() {
            return visitaPedidoCalendar;
          },
          onDeleted: function() {
            window.location.reload();
          }
        });
      }

      function getData(element, name) {
        return element ? (element.getAttribute('data-' + name) || '') : '';
      }

      function removeAmpliacionMensaje(modal) {
        var existing = modal.querySelector('.modal-body #ampliacionMensaje');
        if (existing) {
          existing.remove();
        }
      }

      function appendAmpliacionMensaje(modal, className, message) {
        removeAmpliacionMensaje(modal);
        var body = modal.querySelector('.modal-body');
        if (!body) return;
        body.insertAdjacentHTML('beforeend', '<div id="ampliacionMensaje" class="alert ' + className + '">' + message + '</div>');
      }

      function setFieldValue(modal, selector, value) {
        var element = modal.querySelector(selector);
        if (element) {
          element.value = value;
        }
      }

      function resetAmpliacion(modal, checkboxSelector, previousIdSelector) {
